import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const SearchBuses = () => {
  const [searchData, setSearchData] = useState({
    source: '',
    destination: '',
    date: ''
  });
  const [errors, setErrors] = useState({});
  const navigate = useNavigate();

  const cities = [
    'New York', 'Los Angeles', 'Chicago', 'Houston', 'Phoenix',
    'Philadelphia', 'San Antonio', 'San Diego', 'Dallas', 'San Jose'
  ];

  const handleChange = (e) => {
    setSearchData({
      ...searchData,
      [e.target.name]: e.target.value
    });
  };

  const validateForm = () => {
    const newErrors = {};

    if (!searchData.source) {
      newErrors.source = 'Source city is required';
    }

    if (!searchData.destination) {
      newErrors.destination = 'Destination city is required';
    }

    if (searchData.source === searchData.destination) {
      newErrors.destination = 'Source and destination cannot be the same';
    }

    if (!searchData.date) {
      newErrors.date = 'Travel date is required';
    } else {
      const selectedDate = new Date(searchData.date);
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      if (selectedDate < today) {
        newErrors.date = 'Travel date cannot be in the past';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (validateForm()) {
      // Store search data and navigate to bus list
      localStorage.setItem('searchData', JSON.stringify(searchData));
      navigate('/buses');
    }
  };

  const swapCities = () => {
    setSearchData({
      ...searchData,
      source: searchData.destination,
      destination: searchData.source
    });
  };

  // Get today's date in YYYY-MM-DD format for min attribute
  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="card" style={{ maxWidth: '600px', margin: '50px auto' }}>
      <h2>Search Buses</h2>
      <form onSubmit={handleSearch}>
        <div className="form-group">
          <label>From</label>
          <select
            name="source"
            value={searchData.source}
            onChange={handleChange}
          >
            <option value="">Select Source City</option>
            {cities.map(city => (
              <option key={city} value={city}>{city}</option>
            ))}
          </select>
          {errors.source && <div style={{ color: 'red', fontSize: '12px' }}>{errors.source}</div>}
        </div>

        <div style={{ textAlign: 'center', margin: '10px 0' }}>
          <button
            type="button"
            onClick={swapCities}
            style={{
              background: 'none',
              border: '1px solid #ddd',
              borderRadius: '50%',
              width: '30px',
              height: '30px',
              cursor: 'pointer'
            }}
          >
            ⇄
          </button>
        </div>

        <div className="form-group">
          <label>To</label>
          <select
            name="destination"
            value={searchData.destination}
            onChange={handleChange}
          >
            <option value="">Select Destination City</option>
            {cities.map(city => (
              <option key={city} value={city}>{city}</option>
            ))}
          </select>
          {errors.destination && <div style={{ color: 'red', fontSize: '12px' }}>{errors.destination}</div>}
        </div>

        <div className="form-group">
          <label>Travel Date</label>
          <input
            type="date"
            name="date"
            value={searchData.date}
            onChange={handleChange}
            min={today}
          />
          {errors.date && <div style={{ color: 'red', fontSize: '12px' }}>{errors.date}</div>}
        </div>

        <button type="submit" className="btn" style={{ width: '100%' }}>
          Search Buses
        </button>
      </form>
    </div>
  );
};

export default SearchBuses;
